-- 同步 experience 區塊（FRC 萬金油角色 + 官網貢獻）與新增 job-radar 專案
UPDATE sections SET zh = '[{"role": "實驗室專題生", "organization": "元智大學 林書彥教授實驗室", "period": "2025.05 – 現在", "description": "主導 ICU VAP 早期預警研究：設計 Stay-Level 5-Fold 交叉驗證消除公開基準中的 Patient-Level Data Leakage，以 Integrated Gradients 特徵歸因縮減至 4 項非侵入指標，LSTM 達 72h AUROC 0.98–0.99。論文投稿 IEEE GCCE 2026。"}, {"role": "Engineering Advisor & Systems Integrator", "organization": "FRC TEAM 7645", "period": "2023 – 現在", "description": "負責機器人系統架構：多感測器融合、PID 馬達閉迴路控制調校與軟硬體介面定義；引入 LLM 輔助工具，把原本反覆試錯的韌體除錯流程縮短約一週，並把這套除錯思路教給後進，讓他們能從根因分析切入而非逐行亂試。也幫團隊重做了官網，減少公關端要重複回覆的問題。2023 年起持續擔任 Engineering Advisor。"}, {"role": "競賽選手", "organization": "南港高工 NK-MTC 7645", "period": "2020.06 – 2023.09", "description": "團隊裡的萬金油角色：LabVIEW/Arduino 程式、FRC 電路配線、AutoCAD 建模、雷切與 3D 列印機構零件都做過，也跨足 business plan 撰寫與 engineering notebook 紀錄。3 年內出賽 3 場 FRC 國際區域賽（含 2020 中科 5G 區域賽、2022 台灣鴻海區域賽），並代表參加全國技能競賽。"}]', en = '[{"role": "Research Intern", "organization": "Yuan Ze Univ. — Prof. Lin Shu-Yan''s Lab", "period": "2025.05 – Present", "description": "Leading ICU VAP early-warning research: designed Stay-Level 5-Fold CV to eliminate patient-level data leakage in public baselines, and used Integrated Gradients to distill 14 features to 4 non-invasive metrics; LSTM achieves 72h AUROC 0.98–0.99. Paper submitted to IEEE GCCE 2026."}, {"role": "Engineering Advisor & Systems Integrator", "organization": "FRC TEAM 7645", "period": "2023 – Present", "description": "Directing robot systems architecture: multi-sensor fusion, PID closed-loop motor control tuning, and hardware-software interface definition. Introduced LLM-assisted debugging tools that cut roughly a week off the trial-and-error firmware debugging cycle, and now coach newer members to debug from root cause rather than guess-and-check. Also rebuilt the team website to cut down on repetitive PR questions. Engineering Advisor since 2023.", "frc": true}, {"role": "Competitive Athlete", "organization": "Nangang VHS NK-MTC 7645", "period": "2020.06 – 2023.09", "description": "Did a bit of everything for the team: LabVIEW/Arduino programming, FRC electrical wiring, AutoCAD modeling, laser cutting and 3D printing for mechanical parts, plus business plan writing and engineering notebook entries. Competed in 3 FRC international regional events over 3 years (including the 2020 CSIA 5G Regional and 2022 Taiwan Foxconn Regional), and represented the school at the National Skills Competition."}]', updated_at = datetime('now') WHERE key = 'experience';

INSERT INTO projects (id, zh, en, sort_order)
VALUES ('job-radar', '{"id": "job-radar", "category": "大學校外作品", "title": "Job Radar：個人化求職雷達", "period": "2026 – 現在", "description": "每天用 GitHub Actions 自動爬 49 家鎖定公司的職缺（104、Cake、LinkedIn 三來源，每日約 1,300 筆），依自訂權重評分排序，產出靜態儀表板部署在 Cloudflare Pages。沒有後端、沒有資料庫，資料處理和呈現完全分離。", "tags": ["Python", "Playwright", "Web Scraping", "GitHub Actions", "Cloudflare Pages"], "detail": {"purpose": "一般求職平台的排序是「大家都看什麼」，跟「我適不適合」沒有關係。我想要一個以自己的技能背景為中心的系統：自動追蹤我鎖定的數十家公司，用自己定的權重排序，並把「現在學生身分能投的」和「畢業後才能投的」分開看。\n\n所以做了一個每天自己跑、不用開電腦的工具：每天早上 8:30 自動更新一次。", "concept": "資料和呈現分離：爬蟲產出結構化 JSON，建置階段把卡片靜態渲染進單一 HTML，前端 JS 只負責過濾、搜尋、把已投/收藏狀態存在 localStorage。沒有後端、沒有資料庫，純靜態檔案丟 CDN，快也便宜。\n\n三個來源各自的爬法不一樣：104 是逆向公司頁面的前端 API（抓「全部職缺」而不是關鍵字搜尋，避免漏抓）；Cake 的職缺頁是 JS 渲染，用 Playwright headless 抓；LinkedIn 用它公開的訪客職缺端點，純 HTTP 不用登入。三種資料格式不同，最後統一成同一張卡片的 schema，再混合排序。\n\n評分權重（公司適配度、職稱關鍵字、地點通勤圈、經歷門檻、新人友善度）全部外置在 config.json，不用改程式碼就能調整。職缺再依畢業時程分成「現在可投 / 校徵標的 / 畢業後正職池」，避免把「適合」和「現在能投」混在一起看。", "outcome": "目前每天自動更新，三來源合計約 1,300 筆職缺。中途解決的幾個實際問題：\n\n・104 舊版 joblist API 失效後，改成逆向公司頁 SPA 找到現行端點\n・LinkedIn 會擋一般爬蟲，改用公開訪客端點繞過登入限制\n・原本排在本機 Windows 排程，電腦不開就不會跑，後來搬到 GitHub Actions 雲端 cron\n・CI 部署時 token 夾帶看不見的隱形字元導致 deploy 失敗，後來在部署前用 tr -cd 清掉非法字元並印出字串長度做診斷\n・「這是不是新職缺」需要跨次執行記住看過的職缺，把 seen_jobs.json 納入版控解決\n\n個人學業資料（畢業學分、求職策略）放在需登入的私密頁面，公開的職缺雷達和排行榜頁面不含個人資料。", "tech": [{"group": "資料擷取", "items": [{"name": "104 API 逆向", "desc": "舊版 joblist API 停用後，從公司頁 SPA 的前端 bundle 找出現行 /api/companies/{code}/jobs 端點與公司代碼規則，改抓全部職缺而非關鍵字搜尋"}, {"name": "Playwright 動態渲染", "desc": "Cake 職缺頁是 JS 渲染，用 headless browser 等內容載入後再抓取"}, {"name": "LinkedIn 訪客端點", "desc": "用公開的訪客職缺 API（純 HTTP），避開登入牆和一般爬蟲限制"}]}, {"group": "評分與呈現", "items": [{"name": "外置權重評分引擎", "desc": "公司適配度、職稱關鍵字、地點、經歷門檻等權重全部寫在 config.json，調整排序不用改程式碼"}, {"name": "靜態儀表板生成", "desc": "build_dashboard.py 把三來源的 JSON 統一成同一張卡片 schema，渲染成單檔 RWD HTML，前端 JS 只做過濾/搜尋/收藏狀態（存 localStorage）"}]}, {"group": "自動化部署", "items": [{"name": "GitHub Actions 排程", "desc": "每日 cron 跑完整流程（爬取→評分→建置→部署），從本機 Windows 排程遷移過來，電腦關機也照跑"}, {"name": "CI 部署除錯", "desc": "Cloudflare 部署 token 夾帶隱形字元導致 header 失敗，部署前用 tr -cd 過濾非法字元並印出長度做診斷"}]}], "demo": "https://job-radar-bck.pages.dev"}}', '{"id": "job-radar", "category": "大學校外作品", "title": "Job Radar: Personalized Job Search Dashboard", "period": "2026 – Present", "description": "A GitHub Actions cron job scrapes ~49 target companies daily from three sources (104, Cake, LinkedIn — about 1,300 listings/day), scores and ranks them against my own criteria, and builds a static dashboard deployed on Cloudflare Pages. No backend, no database — data processing and rendering are fully separated.", "tags": ["Python", "Playwright", "Web Scraping", "GitHub Actions", "Cloudflare Pages"], "detail": {"purpose": "Most job boards rank listings by general popularity, which has nothing to do with whether a role actually fits me. I wanted a system centered on my own skills and constraints: track the companies I''m targeting, rank them by weights I set myself, and separate \"what I can apply to as a student now\" from \"what''s only open after graduation.\"\n\nSo I built a tool that runs itself every morning at 8:30 without needing my computer on.", "concept": "Data and presentation are separated: the scraper produces structured JSON, the build step statically renders cards into a single HTML file, and the frontend JS only handles filtering, search, and saved/applied status (stored in localStorage). No backend, no database — just static files on a CDN, fast and cheap.\n\nEach source needs a different scraping approach: 104 uses a reverse-engineered company-page API (pulling \"all listings\" instead of keyword search, to avoid missing postings); Cake''s job pages are JS-rendered, so I use Playwright headless; LinkedIn uses its public guest job endpoint over plain HTTP, no login needed. The three sources have different formats, so I normalize them into one card schema before merging and ranking.\n\nScoring weights (company fit, title keyword matches, commute zone, experience requirements, junior-friendliness) all live in config.json so I can tune them without touching code. Listings are also bucketed by my graduation timeline into \"apply now / campus recruiting targets / post-graduation pool\" so \"a good fit\" and \"something I can apply to right now\" don''t get conflated.", "outcome": "It updates automatically every day, pulling roughly 1,300 listings across the three sources. A few real problems I had to fix along the way:\n\n- 104''s old joblist API was discontinued, so I reverse-engineered the company-page SPA to find the current endpoint\n- LinkedIn blocks generic scrapers, so I switched to its public guest endpoint to get around the login wall\n- It originally ran on a local Windows scheduled task, which meant nothing happened if my computer was off — moved it to GitHub Actions cron\n- CI deploys started failing because the Cloudflare token had invisible characters in it; fixed by stripping non-printable characters with tr -cd and printing the string length to diagnose\n- Telling \"is this a new listing\" apart required remembering what I''d seen across runs, solved by committing seen_jobs.json to version control\n\nPersonal academic data (graduation credits, application strategy) lives behind a login-protected page; the public job radar and rankings pages don''t contain personal data.", "tech": [{"group": "Data Collection", "items": [{"name": "104 API reverse engineering", "desc": "After the old joblist API was discontinued, found the current /api/companies/{code}/jobs endpoint and company-code scheme from the company-page SPA''s frontend bundle, pulling all listings instead of keyword search"}, {"name": "Playwright dynamic rendering", "desc": "Cake''s job pages are JS-rendered, so I use a headless browser and wait for content to load before scraping"}, {"name": "LinkedIn guest endpoint", "desc": "Uses LinkedIn''s public guest job API (plain HTTP) to avoid the login wall and typical scraper blocks"}]}, {"group": "Scoring & Presentation", "items": [{"name": "Externalized scoring engine", "desc": "Company fit, title keywords, location, experience thresholds, etc. all live in config.json, so ranking changes don''t require code edits"}, {"name": "Static dashboard generation", "desc": "build_dashboard.py normalizes the three sources'' JSON into one card schema and renders a single responsive HTML file; frontend JS only handles filtering/search/saved status (localStorage)"}]}, {"group": "Automation & Deployment", "items": [{"name": "GitHub Actions cron", "desc": "A daily cron runs the full pipeline (scrape -> score -> build -> deploy); migrated from a local Windows scheduled task so it still runs with the computer off"}, {"name": "CI deploy debugging", "desc": "A Cloudflare deploy token with invisible characters was breaking request headers; fixed by stripping non-printable characters with tr -cd before deploy and printing the string length to diagnose"}]}], "demo": "https://job-radar-bck.pages.dev"}}', (SELECT COALESCE(MAX(sort_order), -1) + 1 FROM projects));
